namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResponse
{
    public float MacroAccuracy { get; set; }
    public float MicroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategory { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationResponse _evaluationMetrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate(
                "Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);

        // Extract ordered category labels from the key mapping
        var labelCol = split.TrainSet.Schema["Label"];
        var keyType = labelCol.Type as KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        split.TrainSet.Schema["Label"].GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues()
            .Select(v => v.ToString())
            .ToArray();

        _evaluationMetrics = Evaluate(split.TestSet);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    private EvaluationResponse Evaluate(IDataView testSet)
    {
        var predictions = _model.Transform(testSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        var confusionMatrix = metrics.ConfusionMatrix;
        var perCategory = new List<CategoryMetric>();

        for (int i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            perCategory.Add(new CategoryMetric
            {
                Category = i < _categoryLabels.Length ? _categoryLabels[i] : $"Class {i}",
                Precision = Math.Round(confusionMatrix.PerClassPrecision[i], 4),
                Recall = Math.Round(confusionMatrix.PerClassRecall[i], 4),
                F1Score = confusionMatrix.PerClassPrecision[i] + confusionMatrix.PerClassRecall[i] > 0
                    ? Math.Round(
                        2.0 * confusionMatrix.PerClassPrecision[i] * confusionMatrix.PerClassRecall[i]
                        / (confusionMatrix.PerClassPrecision[i] + confusionMatrix.PerClassRecall[i]), 4)
                    : 0
            });
        }

        return new EvaluationResponse
        {
            MacroAccuracy = (float)Math.Round(metrics.MacroAccuracy, 4),
            MicroAccuracy = (float)Math.Round(metrics.MicroAccuracy, 4),
            LogLoss = (float)Math.Round(metrics.LogLoss, 4),
            LogLossReduction = (float)Math.Round(metrics.LogLossReduction, 4),
            PerCategory = perCategory
        };
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = (float)Math.Round(prediction.Score[i], 4);
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        };
    }

    public EvaluationResponse GetEvaluationMetrics() => _evaluationMetrics;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> GetMetrics()
    {
        return Ok(_classifier.GetEvaluationMetrics());
    }
}

